def _power_bi_dataflow_to_nested(
    power_bi_dataflow: PowerBIDataflow,
) -> PowerBIDataflowNested:
    """Convert flat PowerBIDataflow to nested format."""
    attrs = PowerBIDataflowAttributes()
    _populate_power_bi_dataflow_attrs(attrs, power_bi_dataflow)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        power_bi_dataflow,
        _POWER_BI_DATAFLOW_REL_FIELDS,
        PowerBIDataflowRelationshipAttributes,
    )
    return PowerBIDataflowNested(
        guid=power_bi_dataflow.guid,
        type_name=power_bi_dataflow.type_name,
        status=power_bi_dataflow.status,
        version=power_bi_dataflow.version,
        create_time=power_bi_dataflow.create_time,
        update_time=power_bi_dataflow.update_time,
        created_by=power_bi_dataflow.created_by,
        updated_by=power_bi_dataflow.updated_by,
        classifications=power_bi_dataflow.classifications,
        classification_names=power_bi_dataflow.classification_names,
        meanings=power_bi_dataflow.meanings,
        labels=power_bi_dataflow.labels,
        business_attributes=power_bi_dataflow.business_attributes,
        custom_attributes=power_bi_dataflow.custom_attributes,
        pending_tasks=power_bi_dataflow.pending_tasks,
        proxy=power_bi_dataflow.proxy,
        is_incomplete=power_bi_dataflow.is_incomplete,
        provenance_type=power_bi_dataflow.provenance_type,
        home_id=power_bi_dataflow.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _power_bi_dataflow_from_nested(nested: PowerBIDataflowNested) -> PowerBIDataflow:
    """Convert nested format to flat PowerBIDataflow."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else PowerBIDataflowAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _POWER_BI_DATAFLOW_REL_FIELDS,
        PowerBIDataflowRelationshipAttributes,
    )
    return PowerBIDataflow(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_power_bi_dataflow_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _power_bi_dataflow_to_nested_bytes(
    power_bi_dataflow: PowerBIDataflow, serde: Serde
) -> bytes:
    """Convert flat PowerBIDataflow to nested JSON bytes."""
    return serde.encode(_power_bi_dataflow_to_nested(power_bi_dataflow))


def _power_bi_dataflow_from_nested_bytes(data: bytes, serde: Serde) -> PowerBIDataflow:
    """Convert nested JSON bytes to flat PowerBIDataflow."""
    nested = serde.decode(data, PowerBIDataflowNested)
    return _power_bi_dataflow_from_nested(nested)


